-- 2026-06-05 - Coca-Cola CCNA logo: re-cropped to remove huge vertical
-- whitespace padding.
--
-- Source Coca-Cola Script Logo.png is 1651x1275 but the red script only
-- occupies ~1382x399 inside (31% of the image height was empty white
-- padding top + bottom). At object-fit:contain inside the 80px Slide 10
-- logo slot, all that empty space letterboxed the actual logo to a thin
-- strip and it looked smaller than every other vendor logo.
--
-- Re-cropped to the real content bbox + ~6/10%% margin, re-encoded PNG,
-- and upserted in place. Idempotent: same id, ON CONFLICT DO UPDATE.

BEGIN;

INSERT INTO public.deck_gallery (id, slot_key, label, category, vendor_id, data_url, notes, updated_at) VALUES
  ('g_vendor_V00033_logo', NULL, 'Coca-Cola CCNA logo', 'vendor', 'V00033', 'data:image/png;base64,',
   'Re-cropped 2026-06-05 via fix_cocacola_logo.py - 262169 bytes (PNG)', now())
ON CONFLICT (id) DO UPDATE SET
  data_url   = EXCLUDED.data_url,
  label      = EXCLUDED.label,
  category   = EXCLUDED.category,
  vendor_id  = EXCLUDED.vendor_id,
  slot_key   = EXCLUDED.slot_key,
  notes      = EXCLUDED.notes,
  updated_at = EXCLUDED.updated_at;

COMMIT;

-- Verify:
--   SELECT id, label, vendor_id, length(data_url) AS bytes
--     FROM public.deck_gallery WHERE id = 'g_vendor_V00033_logo';
--   -- Expect: 1 row, bytes much smaller than the pre-crop value.
